/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp). */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) {
      throw new ParseException("Expected end of input but found: " + t);
    }
    return result;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <def>+ in <exp>
    *           | map <id-list> to <exp>
    *           | <term> { <binop> <term> }*   (left-associatively!)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF)  return parseIf();
    if (t == Lexer.LET) return parseLet();
    if (t == Lexer.MAP) return parseMap();
    return parseBinaryExp();
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private If parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token t = in.readToken();
    if (t != Lexer.THEN)
      throw new ParseException("Expected 'then' but found: " + t);
    AST conseq = parseExp();
    t = in.readToken();
    if (t != Lexer.ELSE)
      throw new ParseException("Expected 'else' but found: " + t);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp>
    * Def ::= Id := Exp ;
    */
  private Let parseLet() {
    in.readToken(); // consume 'let'
    List<Def> defs = new ArrayList<Def>();
    // Parse one or more Defs until we see 'in'
    Token t = in.peek();
    if (t == Lexer.IN)
      throw new ParseException("Expected at least one definition in let");
    while (in.peek() != Lexer.IN) {
      if (in.peek() == null)
        throw new ParseException("Unexpected end of input inside let");
      defs.add(parseDef());
    }
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: Id := Exp ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable))
      throw new ParseException("Expected variable in definition but found: " + t);
    Variable lhs = (Variable) t;
    t = in.readToken();
    if (t != Lexer.BIND)
      throw new ParseException("Expected ':=' in definition but found: " + t);
    AST rhs = parseExp();
    t = in.readToken();
    if (t != SemiColon.ONLY)
      throw new ParseException("Expected ';' after definition but found: " + t);
    return new Def(lhs, rhs);
  }

  /** Parses: map <id-list> to <exp> */
  private Map parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token t = in.readToken();
    if (t != Lexer.TO)
      throw new ParseException("Expected 'to' in map expression but found: " + t);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: IdList ::= { PropIdList }
    *          PropIdList ::= Id { , Id }*
    */
  private Variable[] parseIdList() {
    List<Variable> vars = new ArrayList<Variable>();
    Token t = in.peek();
    if (t instanceof Variable) {
      in.readToken();
      vars.add((Variable) t);
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        t = in.readToken();
        if (!(t instanceof Variable))
          throw new ParseException("Expected variable after ',' in id list but found: " + t);
        vars.add((Variable) t);
      }
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: BinaryExp ::= Term { BinOp Term }*   (left-associatively) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (!(t instanceof OpToken) || !((OpToken) t).isBinOp()) break;
      in.readToken(); // consume the BinOp token
      BinOp op = ((OpToken) t).toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
    }
    return left;
  }

  /** Parses:
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Empty | Int | Bool
    */
  private AST parseTerm() {
    Token t = in.peek();

    // Unop Term
    if (t instanceof OpToken && ((OpToken) t).isUnOp()) {
      in.readToken(); // consume unop
      UnOp op = ((OpToken) t).toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    }

    // Int constant (not applicable for function application)
    if (t instanceof IntConstant) {
      in.readToken();
      return (IntConstant) t;
    }

    // Bool constant
    if (t instanceof BoolConstant) {
      in.readToken();
      return (BoolConstant) t;
    }

    // Empty constant
    if (t instanceof EmptyConstant) {
      in.readToken();
      return (EmptyConstant) t;
    }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    if (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' in application but found: " + close);
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: Factor ::= ( Exp ) | Prim | Id */
  private AST parseFactor() {
    Token t = in.readToken();
    if (t == null)
      throw new ParseException("Unexpected end of input in expression");
    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' but found: " + close);
      return exp;
    }
    if (t instanceof PrimFun) return (PrimFun) t;
    if (t instanceof Variable) return (Variable) t;
    throw new ParseException("Unexpected token in expression: " + t);
  }

  /** Parses: ExpList ::= { PropExpList }
    *          PropExpList ::= Exp { , Exp }*
    */
  private AST[] parseExpList() {
    List<AST> expList = new ArrayList<AST>();
    if (in.peek() != RightParen.ONLY && in.peek() != null) {
      expList.add(parseExp());
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        expList.add(parseExp());
      }
    }
    return expList.toArray(new AST[0]);
  }
}

import junit.framework.*;
import java.io.*;

/** Comprehensive agent tests for the Jam Parser. */
public class ParserAgentTest extends TestCase {

  public ParserAgentTest(String name) {
    super(name);
  }

  /** Helper: parse program and compare toString output. */
  protected void checkString(String name, String expected, String program) {
    Parser p = new Parser(new StringReader(program));
    assertEquals(name, expected, p.parse().toString());
  }

  /** Helper: assert ParseException is thrown. */
  protected void checkError(String name, String program) {
    try {
      Parser p = new Parser(new StringReader(program));
      p.parse();
      fail(name + ": expected ParseException but got none");
    } catch (ParseException e) {
      // expected
    }
  }

  // ---- Basic literals ----

  public void testIntConstant() {
    checkString("int 0", "0", "0");
    checkString("int 42", "42", "42");
    checkString("int 1000", "1000", "1000");
  }

  public void testBoolConstant() {
    checkString("true", "true", "true");
    checkString("false", "false", "false");
  }

  public void testEmptyConstant() {
    checkString("empty", "empty", "empty");
  }

  public void testVariable() {
    checkString("var x", "x", "x");
    checkString("var abc", "abc", "abc");
    checkString("var x1", "x1", "x1");
  }

  public void testPrimFuns() {
    checkString("number?", "number?", "number?");
    checkString("function?", "function?", "function?");
    checkString("list?", "list?", "list?");
    checkString("empty?", "empty?", "empty?");
    checkString("cons?", "cons?", "cons?");
    checkString("arity", "arity", "arity");
    checkString("cons", "cons", "cons");
    checkString("first", "first", "first");
    checkString("rest", "rest", "rest");
  }

  // ---- Unary operators ----

  public void testUnOpMinus() {
    checkString("unary minus", "- 3", "-3");
  }

  public void testUnOpPlus() {
    checkString("unary plus", "+ 3", "+3");
  }

  public void testUnOpNot() {
    checkString("not true", "~ true", "~true");
    checkString("not false", "~ false", "~false");
  }

  public void testUnOpChain() {
    checkString("double minus", "- - 3", "--3");
    checkString("not not", "~ ~ true", "~~true");
  }

  public void testUnOpVar() {
    checkString("neg var", "- x", "-x");
  }

  // ---- Binary operators ----

  public void testBinOpAdd() {
    checkString("add", "(2 + 3)", "2+3");
  }

  public void testBinOpSub() {
    checkString("sub", "(5 - 2)", "5-2");
  }

  public void testBinOpTimes() {
    checkString("times", "(3 * 4)", "3*4");
  }

  public void testBinOpDivide() {
    checkString("divide", "(10 / 2)", "10/2");
  }

  public void testBinOpEquals() {
    checkString("equals", "(x = y)", "x=y");
  }

  public void testBinOpNotEquals() {
    checkString("not equals", "(x != y)", "x!=y");
  }

  public void testBinOpLessThan() {
    checkString("less than", "(x < y)", "x<y");
  }

  public void testBinOpGreaterThan() {
    checkString("greater than", "(x > y)", "x>y");
  }

  public void testBinOpLessThanEquals() {
    checkString("lte", "(x <= y)", "x<=y");
  }

  public void testBinOpGreaterThanEquals() {
    checkString("gte", "(x >= y)", "x>=y");
  }

  public void testBinOpAnd() {
    checkString("and", "(a & b)", "a&b");
  }

  public void testBinOpOr() {
    checkString("or", "(a | b)", "a|b");
  }

  // ---- Left associativity ----

  public void testLeftAssocAdd() {
    // 1+2+3 should be ((1+2)+3)
    checkString("left assoc add", "((1 + 2) + 3)", "1+2+3");
  }

  public void testLeftAssocMixed() {
    checkString("left assoc mixed", "((1 + 2) - 3)", "1+2-3");
  }

  public void testLeftAssocFour() {
    checkString("left assoc four", "(((1 + 2) + 3) + 4)", "1+2+3+4");
  }

  // ---- Application ----

  public void testAppEmpty() {
    checkString("app no args", "f()", "f()");
  }

  public void testAppOneArg() {
    checkString("app one arg", "f(x)", "f(x)");
  }

  public void testAppTwoArgs() {
    checkString("app two args", "f(x, y)", "f(x,y)");
  }

  public void testAppThreeArgs() {
    checkString("app three args", "f(x, y, z)", "f(x,y,z)");
  }

  public void testPrimFunApp() {
    checkString("first app", "first(x)", "first(x)");
    checkString("cons app", "cons(x, y)", "cons(x,y)");
    checkString("rest app", "rest(lst)", "rest(lst)");
  }

  public void testAppInExpr() {
    checkString("app in binop", "(f(x) + g(y))", "f(x)+g(y)");
  }

  public void testParenExpr() {
    checkString("paren", "(2 + 3)", "(2+3)");
  }

  public void testParenGrouping() {
    // (2+3)*4 vs 2+3*4
    checkString("paren grouping", "((2 + 3) * 4)", "(2+3)*4");
  }

  // ---- If expressions ----

  public void testIfSimple() {
    checkString("if", "if true then 1 else 2", "if true then 1 else 2");
  }

  public void testIfWithVar() {
    checkString("if var", "if x then y else z", "if x then y else z");
  }

  public void testIfNested() {
    checkString("nested if",
      "if true then if false then 1 else 2 else 3",
      "if true then if false then 1 else 2 else 3");
  }

  public void testIfWithBinop() {
    checkString("if binop",
      "if (x < y) then x else y",
      "if x<y then x else y");
  }

  // ---- Let expressions ----

  public void testLetOneDef() {
    checkString("let one def", "let x := 5; in x", "let x := 5; in x");
  }

  public void testLetTwoDefs() {
    checkString("let two defs",
      "let x := 1; y := 2; in (x + y)",
      "let x := 1; y := 2; in x+y");
  }

  public void testLetComplex() {
    checkString("let complex",
      "let f := map x to x; in f(5)",
      "let f := map x to x; in f(5)");
  }

  // ---- Map expressions ----

  public void testMapEmpty() {
    checkString("map empty", "map  to 0", "map to 0");
  }

  public void testMapOneVar() {
    checkString("map one var", "map x to x", "map x to x");
  }

  public void testMapTwoVars() {
    checkString("map two vars", "map x,y to (x + y)", "map x, y to x+y");
  }

  public void testMapBody() {
    checkString("map if body",
      "map x to if (x = 0) then true else false",
      "map x to if x=0 then true else false");
  }

  // ---- Complex nested expressions ----

  public void testFibLike() {
    checkString("fib like",
      "let f := map n to if (n = 0) then 1 else (n * f((n - 1))); in f(5)",
      "let f := map n to if n=0 then 1 else n*f(n-1); in f(5)");
  }

  public void testUnOpInBinOp() {
    checkString("unop in binop", "(- x + y)", "-x+y");
  }

  public void testBinOpWithParen() {
    checkString("paren arith", "((2 + 3) * (4 - 1))", "(2+3)*(4-1)");
  }

  // ---- Error cases ----

  public void testErrorEmpty() {
    checkError("empty input", "");
  }

  public void testErrorExtraToken() {
    checkError("extra token", "1 2");
  }

  public void testErrorMissingThen() {
    checkError("missing then", "if true 1 else 2");
  }

  public void testErrorMissingElse() {
    checkError("missing else", "if true then 1");
  }

  public void testErrorLetNoIn() {
    checkError("let no in", "let x := 1;");
  }

  public void testErrorLetNoDef() {
    checkError("let no def", "let in x");
  }

  public void testErrorLetMissingSemi() {
    checkError("let missing semi", "let x := 1 in x");
  }

  public void testErrorMapNoTo() {
    checkError("map no to", "map x x");
  }

  public void testErrorUnmatchedParen() {
    checkError("unmatched paren", "(1 + 2");
  }

  public void testErrorBracket() {
    checkError("bracket", "[1]");
  }

  public void testErrorDanglingOp() {
    checkError("dangling op", "1 +");
  }

  public void testErrorColonNotBind() {
    checkError("colon", "x : 5");
  }
}

